code = """import json

# Load data
case_data = locals()['var_functions.query_db_60']
transfer_data = locals()['var_functions.query_db_62']

# Normalize agent IDs
def normalize_id(agent_id):
    if agent_id:
        return agent_id.strip().lstrip('#')
    return None

# Build dictionary of eligible agents
eligible_agents = {}
for record in case_data:
    agent_id = normalize_id(record['ownerid'])
    if agent_id:
        eligible_agents[agent_id] = {'cases': int(record['cases_handled']), 'transfers': 0}

# Count transfers for eligible agents
for record in transfer_data:
    old_agent = normalize_id(record['oldvalue__c'])
    if old_agent and old_agent != 'None' and old_agent in eligible_agents:
        eligible_agents[old_agent]['transfers'] += 1

# Find agent with minimum transfers
min_agent = None
min_transfers = float('inf')

for agent_id, stats in eligible_agents.items():
    transfers = stats['transfers']
    if transfers < min_transfers:
        min_transfers = transfers
        min_agent = agent_id
    elif transfers == min_transfers:
        if agent_id < min_agent:
            min_agent = agent_id

# Return result
print("__RESULT__:")
print(json.dumps(min_agent))"""

